export class JobSearchComponent {
  cdr = inject(ChangeDetectorRef);
  allJobs = [];
  isLoading = true;
  selectedJob = null;
  selectedRecruiter = null; // 🚀 Stocke les infos de l'entreprise à afficher
  searchFilters = {
    title: '',
    location: '',
    experience: '',
    contract: ''
  };
  ngOnInit() {
    this.fetchAvailableJobs();
  }
  fetchAvailableJobs() {
    const token = localStorage.getItem('token');
    const jobsPromise = fetch('http://localhost:3000/api/candidate/jobs/list', {
      method: 'GET',
      headers: {
        'Authorization': token ? `Bearer ${token}` : ''
      }
    }).then(res => res.json());
    const historyPromise = fetch('http://localhost:3000/api/candidate/history', {
      method: 'GET',
      headers: {
        'Authorization': token ? `Bearer ${token}` : ''
      }
    }).then(res => res.json()).catch(() => []);
    Promise.all([jobsPromise, historyPromise]).then(([jobsData, historyData]) => {
      const jobsList = Array.isArray(jobsData) ? jobsData : jobsData.jobs || [];
      const historyList = Array.isArray(historyData) ? historyData : historyData.history || [];
      const appliedJobIds = historyList.map(app => app.job_id);
      this.allJobs = jobsList.map(job => ({
        ...job,
        isAlreadyApplied: appliedJobIds.includes(job.id)
      }));
      this.isLoading = false;
      this.cdr.detectChanges();
    }).catch(() => {
      this.isLoading = false;
    });
