import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-job-search',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './job-search.component.html',
  styleUrls: ['./job-search.component.css']
})
export class JobSearchComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  allJobs: any[] = [];
  isLoading: boolean = true;
  selectedJob: any = null;
  selectedRecruiter: any = null; // 🚀 Stocke les infos de l'entreprise à afficher

  searchFilters = { title: '', location: '', experience: '', contract: '' };

  ngOnInit() { this.fetchAvailableJobs(); }

  fetchAvailableJobs() {
    const token = localStorage.getItem('token');
    const jobsPromise = fetch('http://localhost:3000/api/candidate/jobs/list', {
      method: 'GET', headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    }).then(res => res.json());

    const historyPromise = fetch('http://localhost:3000/api/candidate/history', {
      method: 'GET', headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    }).then(res => res.json()).catch(() => []);

    Promise.all([jobsPromise, historyPromise])
      .then(([jobsData, historyData]) => {
        const jobsList = Array.isArray(jobsData) ? jobsData : (jobsData.jobs || []);
        const historyList = Array.isArray(historyData) ? historyData : (historyData.history || []);
        const appliedJobIds = historyList.map((app: any) => app.job_id);

        this.allJobs = jobsList.map((job: any) => ({
          ...job,
          isAlreadyApplied: appliedJobIds.includes(job.id)
        }));
        this.isLoading = false;
        this.cdr.detectChanges();
      }).catch(() => { this.isLoading = false; });
  }

  // 🚀 INTERROGATION DYNAMIQUE DE LA BASE DE DONNÉES DU RECRUTEUR
  onViewRecruiterProfile(recruiterId: number) {
    if (!recruiterId) return;
    const token = localStorage.getItem('token');
    
    // On appelle une route existante ouverte ou candidat pour lire la table 'users'
    const targetUrl = `http://localhost:3000/api/candidate/profile/details-public/${recruiterId}`;
    
    fetch(targetUrl, {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(res => {
      if (!res.ok) throw new Error();
      return res.json();
    })
    .then(data => {
      this.selectedRecruiter = data;
      this.cdr.detectChanges();
    })
    .catch(() => {
      alert("Impossible de charger la fiche de cette entreprise pour le moment.");
    });
  }
  // 🌟 Découpe les compétences textuelles de la recherche pour la boucle Angular
  getSearchJobSkillsArray(skillsText: string): string[] {
    if (!skillsText) return [];
    return skillsText.split(',').map(s => s.trim()).filter(s => s !== '');
  }

  // 🌟 Découpe les langues textuelles de la recherche pour la boucle Angular
  getSearchJobLanguagesArray(langText: string): string[] {
    if (!langText) return [];
    return langText.split(',').map(s => s.trim()).filter(s => s !== '');
  }

  onCloseRecruiterModal() { this.selectedRecruiter = null; this.cdr.detectChanges(); }
  get filteredJobs() { return this.allJobs.filter(job => { const matchTitle = !this.searchFilters.title.trim() || job.title.toLowerCase().includes(this.searchFilters.title.toLowerCase()) || (job.company_name && job.company_name.toLowerCase().includes(this.searchFilters.title.toLowerCase())); const matchLocation = !this.searchFilters.location.trim() || job.location.toLowerCase().includes(this.searchFilters.location.toLowerCase()); const matchExperience = !this.searchFilters.experience || job.experience_level === this.searchFilters.experience; const matchContract = !this.searchFilters.contract || job.contract_type === this.searchFilters.contract; return matchTitle && matchLocation && matchExperience && matchContract; }); }
  get hasActiveFilters(): boolean { return !!(this.searchFilters.title.trim() || this.searchFilters.location.trim() || this.searchFilters.experience || this.searchFilters.contract); }
  onResetFilters() { this.searchFilters = { title: '', location: '', experience: '', contract: '' }; this.cdr.detectChanges(); }
  onViewJobDetails(job: any) { this.selectedJob = job; this.cdr.detectChanges(); }
  onCloseModal() { this.selectedJob = null; this.cdr.detectChanges(); }
  onOpenApplyModal(job: any) { if (confirm(`Confirmer la postulation ?`)) { const token = localStorage.getItem('token'); fetch('http://localhost:3000/api/candidate/apply', { method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': token ? `Bearer ${token}` : '' }, body: JSON.stringify({ job_id: job.id }) }).then(res => res.json()).then(() => { job.isAlreadyApplied = true; this.selectedJob = null; this.cdr.detectChanges(); }); } }
}
<div class="job-search-container">
  
  <!-- 🔍 ZONE SUPÉRIEURE : RECHERCHE AVANCÉE -->
  <div class="search-advanced-card">
    <div class="advanced-search-grid">
      <div class="search-filter-group">
        <label><i class="bi bi-briefcase"></i> Titre du poste</label>
        <div class="input-with-icon"><i class="bi bi-search"></i><input type="text" [(ngModel)]="searchFilters.title" placeholder="Ex: Angular..."></div>
      </div>
      <div class="search-filter-group">
        <label><i class="bi bi-geo-alt"></i> Ville / Région</label>
        <div class="input-with-icon"><i class="bi bi-map"></i><input type="text" [(ngModel)]="searchFilters.location" placeholder="Ex: Tunis..."></div>
      </div>
      <div class="search-filter-group">
        <label><i class="bi bi-mortarboard"></i> Expérience</label>
        <select [(ngModel)]="searchFilters.experience" class="select-filter-compact">
          <option value="">Tous les niveaux</option>
          <option value="Junior (0-2 ans)">Junior (0-2 ans)</option>
          <option value="Intermédiaire (2-5 ans)">Intermédiaire (2-5 ans)</option>
          <option value="Senior (5+ ans)">Senior (5+ ans)</option>
        </select>
      </div>
      <div class="search-filter-group">
        <label><i class="bi bi-tags"></i> Contrat</label>
        <select [(ngModel)]="searchFilters.contract" class="select-filter-compact">
          <option value="">Tous les contrats</option>
          <option value="CDI">CDI</option>
          <option value="CDD">CDD</option>
          <option value="SIVP">SIVP</option>
        </select>
      </div>
    </div>
    @if (hasActiveFilters) {
      <div class="reset-filters-row"><button type="button" class="btn-reset-filters" (click)="onResetFilters()"><i class="bi bi-x-circle"></i> Réinitialiser</button></div>
    }
  </div>

  <!-- ⏳ CHARGEMENT -->
  @if (isLoading) {
    <div class="loading-state-box"><i class="bi bi-arrow-clockwise spin-animation"></i><p>Chargement...</p></div>
  }

  <!-- 🚀 GRILLE DES CARTES (3 PAR LIGNE) -->
  @if (!isLoading && filteredJobs.length > 0) {
    <div class="jobs-cards-grid-3">
      @for (job of filteredJobs; track job.id) {
        <div class="job-feed-card">
          <div class="card-top-info">
            <div class="company-logo-placeholder">
              @if (job.company_logo) {
                <img [src]="'http://localhost:3000/logos/' + job.company_logo" alt="Logo">
              } @else {
                <i class="bi bi-building"></i>
              }
            </div>
            <div class="job-title-block">
              <h4 class="feed-job-title">{{ job.title }}</h4>
              <!-- 🌟 REND LE NOM CLIQUABLE POUR APPRENDRE PLUS SUR L'ENTREPRISE -->
              <span class="feed-company-name clickable-recruiter" (click)="onViewRecruiterProfile(job.recruiter_id)">
                <i class="bi bi-building-check"></i> {{ job.company_name || 'Entreprise Partenaire' }}
              </span>
            </div>
            <span class="contract-badge-feed">{{ job.contract_type }}</span>
          </div>

          <div class="card-mid-meta">
            <span class="meta-item"><i class="bi bi-geo-alt-fill"></i> {{ job.location }}</span>
            <span class="meta-item"><i class="bi bi-laptop-fill"></i> {{ job.workplace_type }}</span>
            <span class="meta-item"><i class="bi bi-mortarboard-fill"></i> {{ job.experience_level }}</span>
          </div>
          <p class="job-short-desc">{{ job.missions_desc | slice:0:100 }}...</p>

          <div class="card-bottom-actions">
            <button class="btn-consult-job" (click)="onViewJobDetails(job)"><i class="bi bi-eye-fill"></i> Consulter</button>
            @if (job.isAlreadyApplied) {
              <span class="badge-already-applied"><i class="bi bi-check-circle-fill"></i> Déjà postulé</span>
            } @else {
              <button class="btn-apply-now" (click)="onOpenApplyModal(job)">Postuler <i class="bi bi-arrow-right-short"></i></button>
            }
          </div>
        </div>
      }
    </div>
  }

  <!-- 👁️ MODALE 1 : DETAILS DU POSTE (INTEGRATION DU LOGO ALIGNÉ) -->
    <!-- 👁️ MODALE 1 : DETAILS DU POSTE (DESIGN PREMIUM UNIFIÉ) -->
   @if (selectedJob) {
    <div class="modal-overlay" (click)="onCloseModal()">
      <div class="modal-card" (click)="$event.stopPropagation()">
        
        <!-- En-tête fixe -->
        <div class="modal-header">
          <h3><i class="bi bi-file-earmark-text-fill"></i> Détails de l'offre d'emploi</h3>
          <button (click)="onCloseModal()" class="btn-close-modal"><i class="bi bi-x-lg"></i></button>
        </div>

        <!-- Corps de la modale organisé -->
        <div class="modal-body">
          
          <!-- Section Héro : Aligne le Logo à gauche et les infos clés sous forme de badges modernes -->
          <div class="job-hero-section">
            <div class="job-logo-wrapper">
              <img [src]="selectedJob.company_logo ? 'http://localhost:3000/logos/' + selectedJob.company_logo : 'https://placehold.co'" 
                   (error)="$any($event.target).src='https://placehold.co'"
                   alt="Logo entreprise">
            </div>
            
            <div class="job-meta-content">
              <h4 class="job-main-title">{{ selectedJob.title }}</h4>
              <span class="job-company-link" (click)="onViewRecruiterProfile(selectedJob.recruiter_id)">
                <i class="bi bi-building"></i> {{ selectedJob.company_name || 'Entreprise Partenaire' }}
              </span>
              
              <!-- Ligne de badges aérés -->
              <div class="job-badges-row">
                <span class="premium-badge badge-contract"><i class="bi bi-file-earmark-text"></i> {{ selectedJob.contract_type }}</span>
                <span class="premium-badge badge-location"><i class="bi bi-geo-alt-fill"></i> {{ selectedJob.location }}</span>
              </div>
            </div>
          </div>

          <!-- Section 1 : Missions Principales -->
          <div class="job-text-block-section">
            <span class="job-block-title"><i class="bi bi-list-task"></i> Missions principales</span>
            <div class="job-block-card">
              <p style="white-space: pre-line; margin: 0; line-height: 1.65; color: #334155;">{{ selectedJob.missions_desc }}</p>
            </div>
          </div>

          <!-- Section 2 : Profil Requis -->
          <div class="job-text-block-section">
            <span class="job-block-title"><i class="bi bi-person-badge-fill"></i> Profil requis & Prérequis</span>
            <div class="job-block-card">
              <p style="white-space: pre-line; margin: 0; line-height: 1.65; color: #334155;">{{ selectedJob.profile_desc }}</p>
            </div>
          </div>

          <!-- 🚀 TAGS COMPÉTENCES CLÉS & TECHNOLOGIES -->
          @if (selectedJob.skills_desc) {
            <div class="job-text-block-section">
              <span class="job-block-title"><i class="bi bi-tags-fill"></i> Compétences clés & Technologies</span>
              <div class="job-block-card">
                <div class="skills-badge-grid">
                  @for (skill of getSearchJobSkillsArray(selectedJob.skills_desc); track $index) {
                    <span class="skill-tag">
                      <i class="bi bi-check2"></i> {{ skill }}
                    </span>
                  }
                </div>
              </div>
            </div>
          }

          <!-- 🚀 TAGS LANGUES EXIGÉES -->
          @if (selectedJob.languages_desc) {
            <div class="job-text-block-section">
              <span class="job-block-title"><i class="bi bi-translate"></i> Langues exigées</span>
              <div class="job-block-card">
                <div class="skills-badge-grid">
                  @for (lang of getSearchJobLanguagesArray(selectedJob.languages_desc); track $index) {
                    <span class="skill-tag" style="background-color: #faf5ff; color: #6b21a8; border-color: #f3e8ff;">
                      <i class="bi bi-globe"></i> {{ lang }}
                    </span>
                  }
                </div>
              </div>
            </div>
          }

          <!-- Pied de page avec bouton d'action principal -->
          <div class="modal-footer-action-row">
            @if (selectedJob.isAlreadyApplied) {
              <span class="premium-applied-banner"><i class="bi bi-check-circle-fill"></i> Vous avez déjà postulé à cette offre</span>
            } @else {
              <button class="btn-submit-apply-large" (click)="onOpenApplyModal(selectedJob)">
                Envoyer ma candidature <i class="bi bi-arrow-right-short"></i>
              </button>
            }
          </div>
          
        </div>
      </div>
    </div>
  }



  <!-- 🏢 🌟 MODALE 2 : FICHE DU RECRUTEUR EN LIGNE (D'origine, inchangée) -->
  @if (selectedRecruiter) {
    <div class="modal-overlay">
      <div class="modal-card recruiter-profile-card">
        <div class="modal-header">
          <h3><i class="bi bi-building-fill"></i> Fiche de l'entreprise</h3>
          <button (click)="onCloseRecruiterModal()" class="btn-close-modal"><i class="bi bi-x-lg"></i></button>
        </div>
        <div class="modal-body">
          <div class="recruiter-meta-header">
            <div class="large-avatar-placeholder">
              @if (selectedRecruiter.company_logo) {
                <img [src]="'http://localhost:3000/logos/' + selectedRecruiter.company_logo" alt="Logo">
              } @else {
                <i class="bi bi-building" style="font-size: 32px; color: #cbd5e1;"></i>
              }
            </div>
            <div class="recruiter-main-titles">
              <h4>{{ selectedRecruiter.company_name }}</h4>
              <span class="badge-verified"><i class="bi bi-patch-check-fill"></i> Partenaire Verified</span>
            </div>
          </div>

          <div class="recruiter-contact-grid">
            <div class="contact-item"><strong><i class="bi bi-envelope-fill"></i> Email :</strong> <span>{{ selectedRecruiter.email || 'Non spécifié' }}</span></div>
            <div class="contact-item"><strong><i class="bi bi-telephone-fill"></i> Téléphone :</strong> <span>{{ selectedRecruiter.phone || 'Non spécifié' }}</span></div>
            <div class="contact-item span-two"><strong><i class="bi bi-geo-alt-fill"></i> Siège social :</strong> <span>{{ selectedRecruiter.address || 'Non spécifié' }}</span></div>
          </div>

          <div class="detail-block" style="margin-top: 15px;">
            <strong>À propos de l'entreprise :</strong>
            <p class="bio-text-box">{{ selectedRecruiter.company_bio || 'Aucune description fournie par l\'entreprise.' }}</p>
          </div>
        </div>
      </div>
    </div>
  }

</div>
